namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public int TotalRatingPoints { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)TotalRatingPoints / RatingCount : 0;
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private int _nextId;

    public static readonly string[] Categories =
        ["Breakfast", "Lunch", "Dinner", "Desserts", "Snacks"];

    public RecipeService()
    {
        _recipes = GetSeedRecipes();
        _nextId = _recipes.Max(r => r.Id) + 1;
    }

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRatingPoints += stars;
            recipe.RatingCount++;
        }
    }

    public void Add(RecipeSubmission submission)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Description = $"A community-submitted recipe for {submission.Title}.",
            Ingredients = submission.Ingredients
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = submission.Steps
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        });
    }

    private static List<Recipe> GetSeedRecipes() =>
    [
        new()
        {
            Id = 1, Title = "Classic Pancakes", Category = "Breakfast",
            Description = "Fluffy golden pancakes perfect for a weekend morning.",
            Ingredients = ["2 cups flour", "2 eggs", "1½ cups milk", "3 tbsp sugar", "2 tsp baking powder", "Pinch of salt", "2 tbsp melted butter"],
            Steps = ["Mix dry ingredients together.", "Whisk eggs, milk, and melted butter.", "Combine wet and dry mixtures until just blended.", "Cook on a greased griddle over medium heat until bubbles form, then flip."],
            TotalRatingPoints = 18, RatingCount = 4
        },
        new()
        {
            Id = 2, Title = "Avocado Toast", Category = "Breakfast",
            Description = "Simple, delicious, and endlessly customizable.",
            Ingredients = ["2 slices sourdough bread", "1 ripe avocado", "Lemon juice", "Salt and pepper", "Red pepper flakes"],
            Steps = ["Toast the bread until golden.", "Mash avocado with lemon juice, salt, and pepper.", "Spread onto toast and top with red pepper flakes."],
            TotalRatingPoints = 14, RatingCount = 3
        },
        new()
        {
            Id = 3, Title = "Chicken Caesar Wrap", Category = "Lunch",
            Description = "A handheld take on the classic Caesar salad.",
            Ingredients = ["2 flour tortillas", "1 grilled chicken breast, sliced", "Romaine lettuce", "Parmesan cheese", "Caesar dressing", "Croutons"],
            Steps = ["Lay tortillas flat.", "Layer lettuce, chicken, parmesan, and croutons.", "Drizzle with Caesar dressing.", "Roll up tightly and slice in half."],
            TotalRatingPoints = 12, RatingCount = 3
        },
        new()
        {
            Id = 4, Title = "Tomato Basil Soup", Category = "Lunch",
            Description = "A comforting bowl of creamy tomato soup with fresh basil.",
            Ingredients = ["1 can crushed tomatoes", "1 cup vegetable broth", "½ cup heavy cream", "Fresh basil leaves", "2 cloves garlic", "Olive oil", "Salt and pepper"],
            Steps = ["Sauté garlic in olive oil.", "Add crushed tomatoes and broth, simmer 15 minutes.", "Stir in cream and torn basil.", "Blend until smooth and season to taste."],
            TotalRatingPoints = 20, RatingCount = 5
        },
        new()
        {
            Id = 5, Title = "Spaghetti Bolognese", Category = "Dinner",
            Description = "A hearty Italian classic with rich meat sauce.",
            Ingredients = ["400g spaghetti", "500g ground beef", "1 onion, diced", "2 cloves garlic", "1 can crushed tomatoes", "2 tbsp tomato paste", "Olive oil", "Italian seasoning", "Parmesan cheese"],
            Steps = ["Cook spaghetti according to package directions.", "Brown beef with onion and garlic.", "Add tomatoes, paste, and seasoning; simmer 20 minutes.", "Serve sauce over pasta and top with parmesan."],
            TotalRatingPoints = 23, RatingCount = 5
        },
        new()
        {
            Id = 6, Title = "Grilled Salmon", Category = "Dinner",
            Description = "Perfectly grilled salmon with a lemon-herb glaze.",
            Ingredients = ["2 salmon fillets", "2 tbsp olive oil", "1 lemon", "2 cloves garlic, minced", "Fresh dill", "Salt and pepper"],
            Steps = ["Mix olive oil, lemon juice, garlic, and dill.", "Marinate salmon for 15 minutes.", "Grill over medium-high heat, 4–5 minutes per side.", "Serve with lemon wedges."],
            TotalRatingPoints = 9, RatingCount = 2
        },
        new()
        {
            Id = 7, Title = "Chocolate Chip Cookies", Category = "Desserts",
            Description = "Chewy, gooey cookies loaded with chocolate chips.",
            Ingredients = ["2¼ cups flour", "1 cup butter, softened", "¾ cup sugar", "¾ cup brown sugar", "2 eggs", "1 tsp vanilla", "1 tsp baking soda", "2 cups chocolate chips"],
            Steps = ["Cream butter and sugars together.", "Beat in eggs and vanilla.", "Mix in flour and baking soda.", "Fold in chocolate chips.", "Bake at 375°F for 9–11 minutes."],
            TotalRatingPoints = 25, RatingCount = 5
        },
        new()
        {
            Id = 8, Title = "Vanilla Bean Panna Cotta", Category = "Desserts",
            Description = "Silky Italian custard with a vanilla bean finish.",
            Ingredients = ["2 cups heavy cream", "½ cup sugar", "1 vanilla bean", "1 packet gelatin", "3 tbsp cold water", "Fresh berries for garnish"],
            Steps = ["Bloom gelatin in cold water.", "Heat cream, sugar, and vanilla seeds until simmering.", "Stir in gelatin until dissolved.", "Pour into ramekins and refrigerate 4 hours."],
            TotalRatingPoints = 8, RatingCount = 2
        },
        new()
        {
            Id = 9, Title = "Guacamole", Category = "Snacks",
            Description = "Fresh and zesty guacamole for chips or tacos.",
            Ingredients = ["3 ripe avocados", "1 lime", "½ red onion, diced", "1 jalapeño, minced", "Fresh cilantro", "Salt"],
            Steps = ["Mash avocados to desired consistency.", "Stir in lime juice, onion, jalapeño, and cilantro.", "Season with salt and serve immediately."],
            TotalRatingPoints = 16, RatingCount = 4
        },
        new()
        {
            Id = 10, Title = "Trail Mix Energy Bites", Category = "Snacks",
            Description = "No-bake energy bites perfect for on-the-go snacking.",
            Ingredients = ["1 cup oats", "½ cup peanut butter", "⅓ cup honey", "½ cup chocolate chips", "½ cup mixed nuts, chopped", "¼ cup dried cranberries"],
            Steps = ["Mix all ingredients in a bowl.", "Refrigerate 30 minutes.", "Roll into 1-inch balls.", "Store in the fridge up to one week."],
            TotalRatingPoints = 11, RatingCount = 3
        }
    ];
}

