arguments.file_text:
@page "/category/{categoryName}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h2>@CategoryName Recipes</h2>

@if (Recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category yet. <a href="submit">Submit one!</a></div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-2">
        @foreach (var recipe in Recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text">@recipe.Description</p>
                        <div class="text-warning mb-2">
                            @for (int i = 1; i <= 5; i++)
                            {
                                <span>@(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")</span>
                            }
                            <small class="text-muted ms-1">(@recipe.RatingCount ratings)</small>
                        </div>
                        <a href="@($"recipe/{recipe.Id}")" class="btn btn-sm btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;

    private List<RecipeHub.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        var formatted = System.Globalization.CultureInfo.CurrentCulture.TextInfo
            .ToTitleCase(CategoryName.ToLowerInvariant());
        CategoryName = formatted;
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{id:int}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Recipe is not null)
        {
            <li class="breadcrumb-item"><a href="@($"category/{Recipe.Category.ToLowerInvariant()}")">@Recipe.Category</a></li>
            <li class="breadcrumb-item active">@Recipe.Title</li>
        }
    </ol>
</nav>

@if (Recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <div class="card shadow-sm">
        <div class="card-body">
            <h2>@Recipe.Title</h2>
            <p class="text-muted">@Recipe.Description</p>

            <h4 class="mt-4">🧾 Ingredients</h4>
            <ul class="list-group list-group-flush mb-4">
                @foreach (var item in Recipe.Ingredients)
                {
                    <li class="list-group-item">@item</li>
                }
            </ul>

            <h4>📝 Steps</h4>
            <ol class="list-group list-group-numbered list-group-flush mb-4">
                @foreach (var step in Recipe.Steps)
                {
                    <li class="list-group-item">@step</li>
                }
            </ol>

            <hr />
            <h4>⭐ Rate This Recipe</h4>
            <StarRating RecipeId="@Recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeHub.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="d-flex align-items-center gap-2">
    <div class="star-rating" role="group" aria-label="Rate this recipe">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (Submitted ? SubmittedRating : HoverRating) ? "star-filled" : "star-empty")"
                  role="button"
                  aria-label="@star stars"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => HoverRating = star"
                  @onmouseout="() => HoverRating = 0">
                @(star <= (Submitted ? SubmittedRating : (HoverRating > 0 ? HoverRating : (int)Math.Round(CurrentAverage))) ? "★" : "☆")
            </span>
        }
    </div>

    @if (Submitted)
    {
        <span class="badge bg-success">Thanks! You rated @SubmittedRating star@(SubmittedRating != 1 ? "s" : "").</span>
    }
    else
    {
        <small class="text-muted">
            @if (RatingCount > 0)
            {
                @:@CurrentAverage.ToString("0.0") avg — @RatingCount rating@(RatingCount != 1 ? "s" : "")
            }
            else
            {
                @:Be the first to rate!
            }
        </small>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int HoverRating;
    private int SubmittedRating;
    private bool Submitted;
    private double CurrentAverage;
    private int RatingCount;

    protected override void OnParametersSet() => RefreshStats();

    private void SubmitRating(int stars)
    {
        if (Submitted) return;
        RecipeService.AddRating(RecipeId, stars);
        SubmittedRating = stars;
        Submitted = true;
        RefreshStats();
    }

    private void RefreshStats()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h2>📝 Submit a Recipe</h2>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<em>@Submission.Title</em>" has been added.
        <a href="@($"category/{Submission.Category.ToLowerInvariant()}")" class="alert-link">View it in @Submission.Category</a>
        or <button class="btn btn-link p-0 alert-link" @onclick="Reset">submit another</button>.
    </div>
}
else
{
    <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe" class="card shadow-sm p-4">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Submission.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                <option value="">— Select a category —</option>
                @foreach (var cat in RecipeService.Categories)
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Submission.Ingredients"
                           placeholder="One ingredient per line&#10;e.g., 2 cups flour&#10;1 cup sugar" />
            <div class="form-text">Enter one ingredient per line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="Submission.Steps"
                           placeholder="One step per line&#10;e.g., Preheat oven to 350°F&#10;Mix dry ingredients" />
            <div class="form-text">Enter one step per line.</div>
