    <div class="star-rating" role="group" aria-label="Rate this recipe">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= (Submitted ? SubmittedRating : HoverRating) ? "star-filled" : "star-empty")"
                  role="button"
                  aria-label="@star stars"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => HoverRating = star"
                  @onmouseout="() => HoverRating = 0">
                @(star <= (Submitted ? SubmittedRating : (HoverRating > 0 ? HoverRating : (int)Math.Round(CurrentAverage))) ? "★" : "☆")
            </span>
        }
    </div>

    @if (Submitted)
    {
        <span class="badge bg-success">Thanks! You rated @SubmittedRating star@(SubmittedRating != 1 ? "s" : "").</span>
    }
    else
    {
        <small class="text-muted">
            @if (RatingCount > 0)
            {
                @:@CurrentAverage.ToString("0.0") avg — @RatingCount rating@(RatingCount != 1 ? "s" : "")
            }
            else
            {
                @:Be the first to rate!
            }
        </small>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int HoverRating;
    private int SubmittedRating;
    private bool Submitted;
    private double CurrentAverage;
    private int RatingCount;

    protected override void OnParametersSet() => RefreshStats();

    private void SubmitRating(int stars)
    {
        if (Submitted) return;
        RecipeService.AddRating(RecipeId, stars);
        SubmittedRating = stars;
        Submitted = true;
        RefreshStats();
    }

    private void RefreshStats()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

