toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">Submit Recipe</li>
    </ol>
</nav>

<h2>📝 Submit a Recipe</h2>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (SubmitSuccess)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<em>@Submission.Title</em>" has been added.
        <a href="@($"category/{Submission.Category.ToLowerInvariant()}")" class="alert-link">View it in @Submission.Category</a>
        or <button class="btn btn-link p-0 alert-link" @onclick="Reset">submit another</button>.
    </div>
}
else
{
    <EditForm Model="Submission" OnValidSubmit="HandleSubmit" FormName="submitRecipe" class="card shadow-sm p-4">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="Submission.Title" placeholder="e.g., Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="Submission.Category">
                <option value="">— Select a category —</option>
                @foreach (var cat in RecipeService.Categories)
                {
                    <option value="@cat">@cat</option>
                }
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="Submission.Ingredients"
                           placeholder="One ingredient per line&#10;e.g., 2 cups flour&#10;1 cup sugar" />
            <div class="form-text">Enter one ingredient per line.</div>
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="Submission.Steps"
                           placeholder="One step per line&#10;e.g., Preheat oven to 350°F&#10;Mix dry ingredients" />
            <div class="form-text">Enter one step per line.</div>
        </div>

        @if (ValidationError is not null)
        {
            <div class="alert alert-danger">@ValidationError</div>
        }

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeSubmission Submission { get; set; } = new();
    private bool SubmitSuccess;
    private string? ValidationError;

    private void HandleSubmit()
    {
        ValidationError = null;

        if (string.IsNullOrWhiteSpace(Submission.Title))
        {
            ValidationError = "Please enter a recipe title.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Submission.Category))
        {
            ValidationError = "Please select a category.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Submission.Ingredients))
        {
            ValidationError = "Please enter at least one ingredient.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Submission.Steps))
        {
            ValidationError = "Please enter at least one step.";
            return;
        }

        RecipeService.Add(Submission);
        SubmitSuccess = true;
    }

    private void Reset()
    {
        Submission = new();
        SubmitSuccess = false;
        ValidationError = null;
    }
}

